class MainActivity extends AppCompatActivity {
    private EditText usernameEditText;
    private EditText passwordEditText;
    private Button loginButton;
    private Button enableBiometricButton;
    private Button biometricLoginButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (AuthPrefs.isLoggedIn(this) && AuthPrefs.isBiometricEnabled(this)) {
            skipLoginAndOpenHome();
            return;
        }

        setContentView(R.layout.activity_main);

        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        loginButton = findViewById(R.id.loginButton);
        enableBiometricButton = findViewById(R.id.enableBiometricButton);
        biometricLoginButton = findViewById(R.id.biometricLoginButton);

        loginButton.setOnClickListener(v -> performPasswordLogin());
        enableBiometricButton.setOnClickListener(v -> enableBiometricLogin());
        biometricLoginButton.setOnClickListener(v -> authenticateWithBiometric());
    }

    private void performPasswordLogin() {
        String username = usernameEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString().trim();

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Enter username and password", Toast.LENGTH_SHORT).show();
            return;
        }

        if (validateCredentials(username, password)) {
            AuthPrefs.setLoggedIn(this, true);
            Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show();
            openHome();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }

    private void enableBiometricLogin() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int canAuth = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);

        if (canAuth == BiometricManager.BIOMETRIC_SUCCESS) {
            AuthPrefs.setBiometricEnabled(this, true);
            Toast.makeText(this, "Biometric login enabled", Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Biometric authentication not available", Toast.LENGTH_SHORT).show();
        }
    }

    private void authenticateWithBiometric() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int canAuth = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);

        if (canAuth != BiometricManager.BIOMETRIC_SUCCESS) {
            Toast.makeText(this, "Biometric authentication not available", Toast.LENGTH_SHORT).show();
            return;
        }

        Executor executor = ContextCompat.getMainExecutor(this);
        BiometricPrompt biometricPrompt = new BiometricPrompt((FragmentActivity) this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                AuthPrefs.setLoggedIn(MainActivity.this, true);
                skipLoginAndOpenHome();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(MainActivity.this, "Fingerprint not recognized", Toast.LENGTH_SHORT).show();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Toast.makeText(MainActivity.this, errString, Toast.LENGTH_SHORT).show();
            }
        });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Login")
                .setSubtitle("Authenticate using your fingerprint")
                .setNegativeButtonText("Cancel")
                .build();

        biometricPrompt.authenticate(promptInfo);
    }

    private boolean validateCredentials(String username, String password) {
        return "user".equals(username) && "password".equals(password);
    }

    private void openHome() {
        // Replace with your home activity
        Toast.makeText(this, "Opening home screen", Toast.LENGTH_SHORT).show();
    }

    private void skipLoginAndOpenHome() {
        openHome();
        finish();
    }
}

