class LoginActivity extends AppCompatActivity {
    private EditText passwordEditText;
    private Button biometricButton;
    private Button loginButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (AuthPrefs.isBiometricEnabled(this) && AuthPrefs.isLoggedIn(this)) {
            goToHome();
            return;
        }

        setContentView(R.layout.activity_login);
        passwordEditText = findViewById(R.id.passwordEditText);
        biometricButton = findViewById(R.id.biometricButton);
        loginButton = findViewById(R.id.loginButton);

        biometricButton.setOnClickListener(v -> authenticateBiometric());
        loginButton.setOnClickListener(v -> {
            if (checkPassword(passwordEditText.getText().toString())) {
                AuthPrefs.setLoggedIn(this, true);
                goToHome();
            } else {
                Toast.makeText(this, "Wrong password", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void authenticateBiometric() {
        BiometricManager manager = BiometricManager.from(this);
        if (manager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG) != BiometricManager.BIOMETRIC_SUCCESS) {
            Toast.makeText(this, "Biometric not available", Toast.LENGTH_SHORT).show();
            return;
        }

        Executor executor = ContextCompat.getMainExecutor(this);
        BiometricPrompt prompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                AuthPrefs.setLoggedIn(LoginActivity.this, true);
                goToHome();
            }
        });

        BiometricPrompt.PromptInfo info = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Unlock App")
                .setSubtitle("Use fingerprint to continue")
                .setNegativeButtonText("Use password")
                .build();

        prompt.authenticate(info);
    }

    private boolean checkPassword(String password) {
        return "password".equals(password);
    }

    private void goToHome() {
        Toast.makeText(this, "Home", Toast.LENGTH_SHORT).show();
    }
}